module top_module(ALUOp,funct,obf_ALUCon);input [1:0] ALUOp;
	input [5:0] funct;
	output [3:0] obf_ALUCon;

	reg [3:0] obf_ALUCon;

	always @(*) begin
		case(ALUOp)
			2'b00: obf_ALUCon <= 4'b0010;    
			2'b01: obf_ALUCon <= 4'b0110;    
            2'b10 :
              begin
                case (funct)
                  6'b100000: obf_ALUCon <= 4'b0010;
                  6'b100010: obf_ALUCon <= 4'b0110;
                  6'b100101: obf_ALUCon <= 4'b0001;
                  6'b100100: obf_ALUCon <= 4'b0000;
                  6'b101010: obf_ALUCon <= 4'b0111;
                  default: 	 obf_ALUCon <= 4'b0000;
                endcase
              end
			default: obf_ALUCon <= 4'b0000;
		endcase
	end

endmodule
